### Instruction:
Write a function that takes in an array of strings and returns a new array containing the strings with the first letter of each string capitalized.

### Response:
```js
function capitalizeFirstLetter(arr) {
  const newArr = [];

  arr.forEach(str => {
    newArr.push(str[0].toUpperCase() + str.slice(1));
  });

  return newArr;
}
```

### Instruction:
Write a function that takes in an array of numbers and returns the sum of all numbers greater than or equal to 50.

### Response:
```js
function sumGreaterThanOrEqual(arr) {
  let sum = 0;

  arr.forEach(num => {
    if (num >= 50) {
      sum += num;
    }
  });

  return sum;
}
```

